query:
ALTER TABLE users MODIFY COLUMN role ENUM('user', 'admin', 'leader') NOT NULL DEFAULT 'user';

ALTER TABLE work_schedules ADD COLUMN leaderId INT DEFAULT NULL;

ALTER TABLE schedule_allocations ADD COLUMN checkInTime DATETIME DEFAULT NULL;
ALTER TABLE schedule_allocations ADD COLUMN checkOutTime DATETIME DEFAULT NULL;

ALTER TABLE employees ADD COLUMN docFrontUrl TEXT DEFAULT NULL;
ALTER TABLE employees ADD COLUMN docBackUrl TEXT DEFAULT NULL;
ALTER TABLE employees ADD COLUMN rg VARCHAR(30) DEFAULT NULL;

CREATE TABLE IF NOT EXISTS pix_change_requests (
  id INT AUTO_INCREMENT PRIMARY KEY,
  employeeId INT NOT NULL,
  requestedByUserId INT NOT NULL,
  oldPixKey TEXT,
  newPixKey TEXT NOT NULL,
  status ENUM('pendente', 'aprovado', 'rejeitado') NOT NULL DEFAULT 'pendente',
  reviewedByUserId INT DEFAULT NULL,
  reviewNotes TEXT DEFAULT NULL,
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
  updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP NOT NULL
);

